import React from 'react';
import { Card, Stack, Row, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°F',
  forecast,
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      }}
    >
      <Stack direction="vertical" gap={20} align="stretch">
        {/* Header: City and Unit */}
        <Row justify="between" align="center">
          <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {unit}
          </Text>
        </Row>

        {/* Current Temperature and Condition */}
        <Stack direction="vertical" gap={8} align="center" justify="center">
          <Text
            variant="h1"
            weight="bold"
            align="center"
            color="var(--ggui-color-primary-600, #0284c7)"
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              lineHeight: '1',
            }}
          >
            {temperature}
          </Text>
          <Text
            variant="h3"
            weight="medium"
            align="center"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Humidity and Wind Speed Metrics */}
        <Row justify="between" align="center" gap={16}>
          {/* Humidity */}
          <Stack direction="vertical" gap={4} align="center" justify="center">
            <Text
              variant="label"
              weight="medium"
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              align="center"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4} align="center" justify="center">
            <Text
              variant="label"
              weight="medium"
              align="center"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              variant="body"
              weight="semibold"
              align="center"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} mph
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <Divider orientation="horizontal" margin={16} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={8} align="stretch">
          <Text
            variant="label"
            weight="semibold"
            align="center"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            5-Day Forecast
          </Text>
          <Row gap={12} justify="center" align="start" wrap={true}>
            {forecast.map((item, index) => (
              <Box
                key={`forecast-${index}`}
                padding="var(--ggui-spacing-2, 8px)"
                background="var(--ggui-color-primary-50, #f0f9ff)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  minWidth: '90px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: 'var(--ggui-spacing-1, 4px)',
                  border: '1px solid var(--ggui-color-primary-100, #e0f2fe)',
                }}
              >
                {/* Day Label */}
                {item.day && (
                  <Text
                    variant="label"
                    weight="semibold"
                    align="center"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                  >
                    {item.day}
                  </Text>
                )}

                {/* Weather Icon */}
                {item.icon && (
                  <Text
                    variant="body"
                    align="center"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    style={{ fontSize: '24px', lineHeight: '1' }}
                  >
                    {item.icon}
                  </Text>
                )}

                {/* High/Low Temperatures */}
                {item.high !== undefined && item.low !== undefined && (
                  <Text
                    variant="caption"
                    align="center"
                    color="var(--ggui-color-primary-900, #0c4a6e)"
                    style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                  >
                    H:{item.high}° L:{item.low}°
                  </Text>
                )}
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

