import React from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to map weather condition strings to emojis.
 * Defaults to a thermometer if no match is found.
 */
const getConditionEmoji = (condition: string = '') => {
  const normalized = condition.trim().toLowerCase();
  if (normalized.includes('sun') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloud') && normalized.includes('part')) return '⛅';
  if (normalized.includes('cloud')) return '☁️';
  if (normalized.includes('rain') || normalized.includes('shower')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';
  if (normalized.includes('mist') || normalized.includes('fog')) return '🌫️';
  if (normalized.includes('wind')) return '💨';
  return '🌡️';
};

/**
 * WeatherCard Component
 * Displays current weather information and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'San Francisco',
  temperature = 72,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 12,
  unit = '°F',
  forecast = [
    { day: 'Mon', icon: 'Sunny', high: 75, low: 58 },
    { day: 'Tue', icon: 'Cloudy', high: 70, low: 55 },
    { day: 'Wed', icon: 'Rainy', high: 65, low: 52 },
    { day: 'Thu', icon: 'PartlyCloudy', high: 68, low: 54 },
    { day: 'Fri', icon: 'Sunny', high: 74, low: 57 },
  ]
}: Props) {
  // Ensure unit format is consistent
  const displayUnit = unit.startsWith('°') ? unit : `°${unit}`;

  return (
    <Container maxWidth="sm">
      <Card 
        shadow="md" 
        padding={0} 
        style={{ 
          overflow: 'hidden',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)'
        }}
      >
        {/* Header Section with City and Condition Summary */}
        <Box padding={24} style={{ backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
          <Stack gap={4} align="center">
            <Text variant="h2" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-primary-700, #0369a1)">
              Today • {condition}
            </Text>
          </Stack>
        </Box>

        <Stack gap={24} padding={24}>
          {/* Main Temperature and Condition Display */}
          <Stack align="center" gap={0}>
            <Text 
              variant="h1" 
              weight="bold" 
              style={{ 
                fontSize: '4.5rem', 
                lineHeight: 1,
                color: 'var(--ggui-color-onSurface, #18181b)'
              }}
            >
              {temperature}{displayUnit}
            </Text>
            <Text 
              style={{ 
                fontSize: '3rem', 
                marginTop: 'var(--ggui-spacing-2, 8px)',
                lineHeight: 1
              }}
              aria-hidden="true"
            >
              {getConditionEmoji(condition)}
            </Text>
          </Stack>

          {/* Environmental Details (Humidity, Wind) */}
          <Row 
            justify="around" 
            align="center"
            style={{ 
              backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', 
              padding: 'var(--ggui-spacing-4, 16px)', 
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
            }}
          >
            <Stack align="center" gap={2}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>

            <Divider orientation="vertical" margin={0} />

            <Stack align="center" gap={2}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} km/h</Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* 5-Day Forecast Grid */}
          <Stack gap={16}>
            <Text variant="label" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-DAY FORECAST
            </Text>
            <Row justify="between" align="center">
              {forecast.slice(0, 5).map((item, index) => (
                <Stack key={`forecast-${item.day}-${index}`} align="center" gap={8} style={{ flex: 1 }}>
                  <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                    {item.day}
                  </Text>
                  <Text 
                    style={{ fontSize: 'var(--ggui-font-size-xl, 20px)' }}
                    aria-hidden="true"
                  >
                    {getConditionEmoji(item.icon)}
                  </Text>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

