                  style={{ 
                    fontSize: 'var(--ggui-font-size-4xl, 36px)', 
                    lineHeight: 1 
                  }} 
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {Math.round(temperature)}
                </Text>
                <Text 
                  variant="h3" 
                  weight="semibold" 
                  color="var(--ggui-color-primary-600, #0284c7)"
                  style={{ marginTop: '4px' }}
                >
                  °{unit}
                </Text>
              </Row>
              <Text variant="h3" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {condition}
              </Text>
            </Stack>

            <Box style={{ fontSize: '64px' }} aria-hidden="true">
              {getConditionEmoji(condition)}
            </Box>
          </Row>

          {/* Secondary Details Section */}
          <Row 
            gap={16} 
            style={{ 
              background: 'var(--ggui-color-surface, #fafafa)', 
              padding: 'var(--ggui-spacing-4, 16px)', 
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)'
            }}
          >
            <Stack gap={2} align="center" style={{ flex: 1 }}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">HUMIDITY</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack gap={2} align="center" style={{ flex: 1 }}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">WIND SPEED</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} mph</Text>
            </Stack>
          </Row>

          <Divider />

          {/* 5-Day Forecast Strip */}
          <Stack gap={12}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-Day Forecast</Text>
            <Row justify="between" align="center" gap={8} wrap>
              {forecast.map((item, index) => (
                <Stack 
                  key={index} 
                  align="center" 
                  gap={4} 
                  style={{ 
                    minWidth: '60px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)'
                  }}
                >
                  <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day?.toUpperCase()}
                  </Text>
                  <Box style={{ fontSize: '24px' }}>
                    {item.icon || '☁️'}
                  </Box>
                  <Row gap={4} justify="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                      {item.high}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {item.low}°
                    </Text>
                  </Row>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
